import '../lib/proxy_policy.dart';
import '../lib/request_origin.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final cidrPolicy = TrustedProxyPolicy(['10.42.16.0/20']);
  check(cidrPolicy.trusts('10.42.31.254'), 'an address inside the configured range is trusted');
  check(!cidrPolicy.trusts('10.42.32.1'), 'an address outside the configured range is rejected');

  final resolver = ExternalOriginResolver(
    TrustedProxyPolicy(['10.0.0.9', '10.0.1.4']),
  );
  final result = resolver.resolve(const RequestMetadata(
    remoteAddress: '10.0.0.9',
    scheme: 'http',
    host: 'service.internal',
    headers: {
      'x-forwarded-for': '192.0.2.66, 203.0.113.40, 10.0.1.4',
      'x-forwarded-proto': 'http, https, http',
      'x-forwarded-host': 'spoof.invalid, api.example.test, edge.internal',
    },
  ));
  check(result.clientAddress == '203.0.113.40', 'the first untrusted hop is the client');
  check(result.scheme == 'https', 'scheme is selected from the same trusted boundary');
  check(result.host == 'api.example.test', 'host is selected from the same trusted boundary');
}
